import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as d,c,e as o}from"./app.7aa27cff.js";const a={},n=o(`<h1 id="_10-1-\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u65B9\u6CD5\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#_10-1-\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u65B9\u6CD5\u7B80\u4ECB" aria-hidden="true">#</a> 10.1 \u81EA\u5B9A\u4E49\u7EC4\u4EF6\u65B9\u6CD5\u7B80\u4ECB</h1><p>\u5F53Flutter\u63D0\u4F9B\u7684\u73B0\u6709\u7EC4\u4EF6\u65E0\u6CD5\u6EE1\u8DB3\u6211\u4EEC\u7684\u9700\u6C42\uFF0C\u6216\u8005\u6211\u4EEC\u4E3A\u4E86\u5171\u4EAB\u4EE3\u7801\u9700\u8981\u5C01\u88C5\u4E00\u4E9B\u901A\u7528\u7EC4\u4EF6\uFF0C\u8FD9\u65F6\u6211\u4EEC\u5C31\u9700\u8981\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u3002\u5728Flutter\u4E2D\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u6709\u4E09\u79CD\u65B9\u5F0F\uFF1A\u901A\u8FC7\u7EC4\u5408\u5176\u5B83\u7EC4\u4EF6\u3001\u81EA\u7ED8\u548C\u5B9E\u73B0RenderObject\u3002\u672C\u8282\u6211\u4EEC\u5148\u5206\u522B\u4ECB\u7ECD\u4E00\u4E0B\u8FD9\u4E09\u79CD\u65B9\u5F0F\u7684\u7279\u70B9\uFF0C\u540E\u9762\u7AE0\u8282\u4E2D\u5219\u8BE6\u7EC6\u4ECB\u7ECD\u5B83\u4EEC\u7684\u7EC6\u8282\u3002</p><h3 id="\u7EC4\u5408\u591A\u4E2Awidget" tabindex="-1"><a class="header-anchor" href="#\u7EC4\u5408\u591A\u4E2Awidget" aria-hidden="true">#</a> \u7EC4\u5408\u591A\u4E2AWidget</h3><p>\u8FD9\u79CD\u65B9\u5F0F\u662F\u901A\u8FC7\u62FC\u88C5\u591A\u4E2A\u7EC4\u4EF6\u6765\u7EC4\u5408\u6210\u4E00\u4E2A\u65B0\u7684\u7EC4\u4EF6\u3002\u4F8B\u5982\u6211\u4EEC\u4E4B\u524D\u4ECB\u7ECD\u7684<code>Container</code>\u5C31\u662F\u4E00\u4E2A\u7EC4\u5408\u7EC4\u4EF6\uFF0C\u5B83\u662F\u7531<code>DecoratedBox</code>\u3001<code>ConstrainedBox</code>\u3001<code>Transform</code>\u3001<code>Padding</code>\u3001<code>Align</code>\u7B49\u7EC4\u4EF6\u7EC4\u6210\u3002</p><p>\u5728Flutter\u4E2D\uFF0C\u7EC4\u5408\u7684\u601D\u60F3\u975E\u5E38\u91CD\u8981\uFF0CFlutter\u63D0\u4F9B\u4E86\u975E\u5E38\u591A\u7684\u57FA\u7840\u7EC4\u4EF6\uFF0C\u800C\u6211\u4EEC\u7684\u754C\u9762\u5F00\u53D1\u5176\u5B9E\u5C31\u662F\u6309\u7167\u9700\u8981\u7EC4\u5408\u8FD9\u4E9B\u7EC4\u4EF6\u6765\u5B9E\u73B0\u5404\u79CD\u4E0D\u540C\u7684\u5E03\u5C40\u800C\u5DF2\u3002</p><h3 id="\u81EA\u7ED8" tabindex="-1"><a class="header-anchor" href="#\u81EA\u7ED8" aria-hidden="true">#</a> \u81EA\u7ED8</h3><p>\u5982\u679C\u9047\u5230\u65E0\u6CD5\u901A\u8FC7\u73B0\u6709\u7684\u7EC4\u4EF6\u6765\u5B9E\u73B0\u9700\u8981\u7684UI\u65F6\uFF0C\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u81EA\u7ED8\u7EC4\u4EF6\u7684\u65B9\u5F0F\u6765\u5B9E\u73B0\uFF0C\u4F8B\u5982\u6211\u4EEC\u9700\u8981\u4E00\u4E2A\u989C\u8272\u6E10\u53D8\u7684\u5706\u5F62\u8FDB\u5EA6\u6761\uFF0C\u800CFlutter\u63D0\u4F9B\u7684<code>CircularProgressIndicator</code>\u5E76\u4E0D\u652F\u6301\u5728\u663E\u793A\u7CBE\u786E\u8FDB\u5EA6\u65F6\u5BF9\u8FDB\u5EA6\u6761\u5E94\u7528\u6E10\u53D8\u8272\uFF08\u5176<code>valueColor</code> \u5C5E\u6027\u53EA\u652F\u6301\u6267\u884C\u65CB\u8F6C\u52A8\u753B\u65F6\u53D8\u5316Indicator\u7684\u989C\u8272\uFF09\uFF0C\u8FD9\u65F6\u6700\u597D\u7684\u65B9\u6CD5\u5C31\u662F\u901A\u8FC7\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u6765\u7ED8\u5236\u51FA\u6211\u4EEC\u671F\u671B\u7684\u5916\u89C2\u3002\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7Flutter\u4E2D\u63D0\u4F9B\u7684<code>CustomPaint</code>\u548C<code>Canvas</code>\u6765\u5B9E\u73B0UI\u81EA\u7ED8\u3002</p><h3 id="\u5B9E\u73B0renderobject" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u73B0renderobject" aria-hidden="true">#</a> \u5B9E\u73B0RenderObject</h3><p>Flutter\u63D0\u4F9B\u7684\u81EA\u8EAB\u5177\u6709UI\u5916\u89C2\u7684\u7EC4\u4EF6\uFF0C\u5982\u6587\u672C<code>Text</code>\u3001<code>Image</code>\u90FD\u662F\u901A\u8FC7\u76F8\u5E94\u7684<code>RenderObject</code>\uFF08\u6211\u4EEC\u5C06\u5728\u201CFlutter\u6838\u5FC3\u539F\u7406\u201D\u4E00\u7AE0\u4E2D\u8BE6\u7EC6\u4ECB\u7ECD<code>RenderObject</code>\uFF09\u6E32\u67D3\u51FA\u6765\u7684\uFF0C\u5982Text\u662F\u7531<code>RenderParagraph</code>\u6E32\u67D3\uFF1B\u800C<code>Image</code>\u662F\u7531<code>RenderImage</code>\u6E32\u67D3\u3002<code>RenderObject</code>\u662F\u4E00\u4E2A\u62BD\u8C61\u7C7B\uFF0C\u5B83\u5B9A\u4E49\u4E86\u4E00\u4E2A\u62BD\u8C61\u65B9\u6CD5<code>paint(...)</code>\uFF1A</p><div class="language-dart ext-dart line-numbers-mode"><pre class="language-dart"><code><span class="token keyword">void</span> <span class="token function">paint</span><span class="token punctuation">(</span><span class="token class-name">PaintingContext</span> context<span class="token punctuation">,</span> <span class="token class-name">Offset</span> offset<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>PaintingContext</code>\u4EE3\u8868\u7EC4\u4EF6\u7684\u7ED8\u5236\u4E0A\u4E0B\u6587\uFF0C\u901A\u8FC7<code>PaintingContext.canvas</code>\u53EF\u4EE5\u83B7\u5F97<code>Canvas</code>\uFF0C\u800C\u7ED8\u5236\u903B\u8F91\u4E3B\u8981\u662F\u901A\u8FC7<code>Canvas</code> API\u6765\u5B9E\u73B0\u3002\u5B50\u7C7B\u9700\u8981\u91CD\u5199\u6B64\u65B9\u6CD5\u4EE5\u5B9E\u73B0\u81EA\u8EAB\u7684\u7ED8\u5236\u903B\u8F91\uFF0C\u5982<code>RenderParagraph</code>\u9700\u8981\u5B9E\u73B0\u6587\u672C\u7ED8\u5236\u903B\u8F91\uFF0C\u800C<code>RenderImage</code>\u9700\u8981\u5B9E\u73B0\u56FE\u7247\u7ED8\u5236\u903B\u8F91\u3002</p><p>\u53EF\u4EE5\u53D1\u73B0\uFF0C<code>RenderObject</code>\u4E2D\u6700\u7EC8\u4E5F\u662F\u901A\u8FC7<code>Canvas</code> API\u6765\u7ED8\u5236\u7684\uFF0C\u90A3\u4E48\u901A\u8FC7\u5B9E\u73B0<code>RenderObject</code>\u7684\u65B9\u5F0F\u548C\u4E0A\u9762\u4ECB\u7ECD\u7684\u901A\u8FC7<code>CustomPaint</code>\u548C<code>Canvas</code>\u81EA\u7ED8\u7684\u65B9\u5F0F\u6709\u4EC0\u4E48\u533A\u522B\uFF1F\u5176\u5B9E\u7B54\u6848\u5F88\u7B80\u5355\uFF0C<code>CustomPaint</code>\u53EA\u662F\u4E3A\u4E86\u65B9\u4FBF\u5F00\u53D1\u8005\u5C01\u88C5\u7684\u4E00\u4E2A\u4EE3\u7406\u7C7B\uFF0C\u5B83\u76F4\u63A5\u7EE7\u627F\u81EA<code>SingleChildRenderObjectWidget</code>\uFF0C\u901A\u8FC7<code>RenderCustomPaint</code>\u7684<code>paint</code>\u65B9\u6CD5\u5C06<code>Canvas</code>\u548C\u753B\u7B14<code>Painter</code>(\u9700\u8981\u5F00\u53D1\u8005\u5B9E\u73B0\uFF0C\u540E\u9762\u7AE0\u8282\u4ECB\u7ECD)\u8FDE\u63A5\u8D77\u6765\u5B9E\u73B0\u4E86\u6700\u7EC8\u7684\u7ED8\u5236\uFF08\u7ED8\u5236\u903B\u8F91\u5728<code>Painter</code>\u4E2D\uFF09\u3002</p><h3 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h3><p>\u201C\u7EC4\u5408\u201D\u662F\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u6700\u7B80\u5355\u7684\u65B9\u6CD5\uFF0C\u5728\u4EFB\u4F55\u9700\u8981\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u7684\u573A\u666F\u4E0B\uFF0C\u6211\u4EEC\u90FD\u5E94\u8BE5\u4F18\u5148\u8003\u8651\u662F\u5426\u80FD\u591F\u901A\u8FC7\u7EC4\u5408\u6765\u5B9E\u73B0\u3002\u800C\u81EA\u7ED8\u548C\u901A\u8FC7\u5B9E\u73B0<code>RenderObject</code>\u7684\u65B9\u6CD5\u672C\u8D28\u4E0A\u662F\u4E00\u6837\u7684\uFF0C\u90FD\u9700\u8981\u5F00\u53D1\u8005\u8C03\u7528<code>Canvas</code> API\u624B\u52A8\u53BB\u7ED8\u5236UI\uFF0C\u4F18\u70B9\u662F\u5F3A\u5927\u7075\u6D3B\uFF0C\u7406\u8BBA\u4E0A\u53EF\u4EE5\u5B9E\u73B0\u4EFB\u4F55\u5916\u89C2\u7684UI\uFF0C\u800C\u7F3A\u70B9\u662F\u5FC5\u987B\u4E86\u89E3<code>Canvas</code> API\u7EC6\u8282\uFF0C\u5E76\u4E14\u5F97\u81EA\u5DF1\u53BB\u5B9E\u73B0\u7ED8\u5236\u903B\u8F91\u3002</p><p>\u5728\u672C\u7AE0\u63A5\u4E0B\u6765\u7684\u5C0F\u8282\u4E2D\uFF0C\u6211\u4EEC\u5C06\u901A\u8FC7\u4E00\u4E9B\u5B9E\u4F8B\u6765\u8BE6\u7EC6\u4ECB\u7ECD\u81EA\u5B9A\u4E49UI\u7684\u8FC7\u7A0B\uFF0C\u7531\u4E8E\u540E\u4E24\u79CD\u65B9\u6CD5\u672C\u8D28\u662F\u76F8\u540C\u7684\uFF0C\u5E76\u4E14Flutter\u4E2D\u5F88\u591A\u57FA\u7840\u7EC4\u4EF6\u90FD\u662F\u901A\u8FC7<code>RenderObject</code>\u7684\u5F62\u5F0F\u6765\u5B9E\u73B0\u7684\uFF0C\u6240\u4EE5\u540E\u7EED\u6211\u4EEC\u53EA\u4ECB\u7ECD<code>CustomPaint</code>\u548C<code>Canvas</code>\u7684\u65B9\u5F0F\uFF0C\u8BFB\u8005\u5982\u679C\u5BF9\u81EA\u5B9A\u4E49<code>RenderObject</code>\u7684\u65B9\u6CD5\u597D\u5947\uFF0C\u53EF\u4EE5\u67E5\u770BFlutter\u4E2D\u76F8\u5173\u57FA\u7840\u7EC4\u4EF6\u5BF9\u5E94\u7684<code>RenderObject</code>\u7684\u5B9E\u73B0\u6E90\u7801\uFF0C\u5982<code>RenderParagraph</code>\u6216<code>RenderImage</code>\u3002</p>`,15),t=[n];function r(s,i){return d(),c("div",null,t)}var h=e(a,[["render",r],["__file","intro.html.vue"]]);export{h as default};
